def to_seller(model: SellerModel) -> Seller:
    return Seller(id=model.id, name=model.name, email=model.email)


def to_category(model: CategoryModel) -> Category:
    return Category(id=model.id, name=model.name)


def to_review(model: ReviewModel) -> Review:
    return Review(
        id=model.id,
        author_name=model.author_name,
        rating=model.rating,
        comment=model.comment,
        created_at=model.created_at,
    )


def to_image(model: ImageModel) -> Image:
    return Image(id=model.id, url=model.url, alt_text=model.alt_text)


def to_product(model: ProductModel) -> Product:
    product = Product(
        id=model.id,
        name=model.name,
        description=model.description,
        price=str(model.price if isinstance(model.price, Decimal) else Decimal(model.price)),
    )
    product._seller = to_seller(model.seller) if model.seller else None
    product._category = to_category(model.category) if model.category else None
    product._reviews = [to_review(r) for r in model.reviews]
    product._images = [to_image(i) for i in model.images]
    return product


